def is_even(f):
    return all(f(x) == f(-x) for x in range(-10, 11))

def is_odd(f):
    return all(f(x) == -f(-x) for x in range(-10, 11))

# Determine if the function is even, odd, or neither
if is_even(f):
    result = "even"
elif is_odd(f):
    result = "odd"
else:
    result = "neither"

print(result)
